  ('social-worker-moex-01231', 'social-worker', 'social-worker-moex-110-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會福利輸送體制的設計，是一連串相互關聯之不同選擇的集合。Gilbert和Terrell（2014）列出 幾個需要考量的向度，下列何者並非為其考量的項目？', '["行政集中化或分散化", "單一的個別體系或綜合式體系", "不同體系間的整合或分散", "成效效率或服務品質之維持"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "6100a28843a9", "answer_pdf_sha1": "6db6a444bcb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
