  ('social-worker-moex-01233', 'social-worker', 'social-worker-moex-110-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關俾斯麥模式與貝佛里奇模式之比較，下列何者錯誤？', '["俾斯麥模式財源主要來自稅收，貝佛里奇模式財源主要來自保險費", "俾斯麥模式以社會保險為基礎，福利資格的取得依據過去的繳費紀錄", "貝佛里奇模式以全體國民為對象", "俾斯麥模式之給付為所得相關，貝佛里奇模式之給付為均一費率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:08+00:00", "source_pdf_sha1": "6100a28843a9", "answer_pdf_sha1": "6db6a444bcb0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
